import { useEffect, useRef, useState, forwardRef, useImperativeHandle } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径
loader.config({
  paths: {
    vs: 'https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs'
  }
})

export interface EditorHandle {
  getSelectedText: () => string
  getCursorPosition: () => { lineNumber: number; column: number }
  insertText: (text: string) => void
  replaceSelection: (text: string) => void
}

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = forwardRef<EditorHandle, EditorProps>(({ value, onChange, filePath }, ref) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const [loading, setLoading] = useState(true)

  // 暴露编辑器方法给父组件
  useImperativeHandle(ref, () => ({
    getSelectedText: () => {
      if (!monacoEditorRef.current) return ''
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return ''
      return monacoEditorRef.current.getModel()?.getValueInRange(selection) || ''
    },
    getCursorPosition: () => {
      if (!monacoEditorRef.current) return { lineNumber: 1, column: 1 }
      const pos = monacoEditorRef.current.getPosition()
      return pos || { lineNumber: 1, column: 1 }
    },
    insertText: (text: string) => {
      if (!monacoEditorRef.current) return
      const position = monacoEditorRef.current.getPosition()
      if (position) {
        const range = new monaco.Range(
          position.lineNumber,
          position.column,
          position.lineNumber,
          position.column
        )
        monacoEditorRef.current.executeEdits('', [
          { range, text }
        ])
      }
    },
    replaceSelection: (text: string) => {
      if (!monacoEditorRef.current) return
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return
      monacoEditorRef.current.executeEdits('', [
        { range: selection, text }
      ])
    },
  }))

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true
    let debounceTimer: ReturnType<typeof setTimeout> | null = null
    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化（带防抖，避免每次按键都触发父组件重渲染）
        editor.onDidChangeModelContent(() => {
          if (debounceTimer) clearTimeout(debounceTimer)
          debounceTimer = setTimeout(() => {
            if (!isMounted || !monacoEditorRef.current) return
            const newValue = editor.getValue()
            onChange(newValue)
          }, 300)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (debounceTimer) clearTimeout(debounceTimer)
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      // 使用 executeEdits 替代 setValue，保留 undo/redo 历史
      const model = monacoEditorRef.current.getModel()
      if (model) {
        monacoEditorRef.current.executeEdits('', [{
          range: model.getFullModelRange(),
          text: value,
        }])
      }
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
})

export default Editor

import { useState, useEffect, useRef, useCallback } from 'react'
import { Layout, Menu, Button, message } from 'antd'
import {
  SaveOutlined,
  FolderOpenOutlined,
  BookOutlined,
  UserOutlined,
  SettingOutlined,
  ThunderboltOutlined,
  SearchOutlined,
} from '@ant-design/icons'
import OutlineTree from './OutlineTree'
import factsStore from '../db'
import Editor, { EditorHandle } from './Editor'
import FactsPanel from './FactsPanel'
import AIToolsPanel from './AIToolsPanel'
import CharactersPage from '../pages/CharactersPage'
import SettingsPage from '../pages/SettingsPage'
import AppSettingsPage from '../pages/AppSettingsPage'
import ProjectManager from './ProjectManager'
import VectorSearchPanel from './VectorSearchPanel'
import AnalysisPanel from './AnalysisPanel'
import ExportManager from './ExportManager'
import type { MenuProps } from 'antd'

const { Sider, Content } = Layout

type TabKey = 'outline' | 'characters' | 'world' | 'facts' | 'search' | 'appSettings'
type RightPanelTab = 'ai' | 'analysis'

// 左侧菜单
const siderMenuItems: MenuProps['items'] = [
  { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
  { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
  { key: 'world', icon: <SettingOutlined />, label: '世界设定' },
  { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
  { key: 'search', icon: <SearchOutlined />, label: '语义检索' },
  { key: 'appSettings', icon: <SettingOutlined />, label: '应用设置' },
]

const Workbench = () => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [rightPanelTab, setRightPanelTab] = useState<RightPanelTab>('ai')
  const [activeChapter, setActiveChapter] = useState<string | null>(null)
  const [chapterContent, setChapterContent] = useState('')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [projectName, setProjectName] = useState<string>('小说')
  const [isDirty, setIsDirty] = useState(false)
  const autoSaveTimerRef = useRef<NodeJS.Timeout | null>(null)
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle')
  const [projectManagerVisible, setProjectManagerVisible] = useState(false)
  const [exportManagerVisible, setExportManagerVisible] = useState(false)
  const editorRef = useRef<EditorHandle>(null)

  // 初始化项目
  useEffect(() => {
    const init = async () => {
      const root = await window.electronAPI.getProjectRoot()
      if (root) {
        setProjectRoot(root)
        await factsStore.setProjectRoot(root)
        // 读取项目名称
        try {
          const result = await window.electronAPI.yaml.read(`${root}/project.yaml`)
          if (result.success && result.data) {
            const data = result.data as Record<string, unknown>
            setProjectName(String(data.title || '小说'))
          }
        } catch {}
      }
    }
    init()
  }, [])


  const handleSave = useCallback(async () => {
    if (!activeChapter || !chapterContent) return

    setSaveStatus('saving')
    try {
      const result = await window.electronAPI.writeFile(activeChapter, chapterContent)
      if (result.success) {
        setIsDirty(false)
        setSaveStatus('saved')
        setTimeout(() => setSaveStatus('idle'), 2000)
      } else {
        setSaveStatus('error')
        message.error(`保存失败：${result.error}`)
        // 保存失败时立即重试一次（捕获当前 chapterContent，避免闭包过期）
        const contentToSave = chapterContent
        setTimeout(async () => {
          setSaveStatus('saving')
          const retry = await window.electronAPI.writeFile(activeChapter, contentToSave)
          if (retry.success) {
            setIsDirty(false)
            setSaveStatus('saved')
            setTimeout(() => setSaveStatus('idle'), 2000)
          } else {
            setSaveStatus('error')
          }
        }, 1000)
      }
    } catch (error) {
      setSaveStatus('error')
      message.error('保存失败')
    }
  }, [activeChapter, chapterContent])

  // 自动保存
  useEffect(() => {
    if (isDirty && activeChapter) {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current)
      autoSaveTimerRef.current = setTimeout(() => {
        handleSave()
      }, 5000)
    }
    return () => {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current)
      autoSaveTimerRef.current = null
    }
  }, [chapterContent, isDirty, activeChapter, handleSave])





  // 打开项目
  const handleOpenProject = () => {
    setProjectManagerVisible(true)
  }

  // 项目打开后的回调
  const handleProjectOpened = async (projectPath: string) => {
    setProjectRoot(projectPath)
    await factsStore.setProjectRoot(projectPath)
    // 同步到 main 进程，否则 main 的路径验证会基于错误的 projectRoot
    await window.electronAPI.setProjectRoot(projectPath)
    // 读取项目名称
    try {
      const result = await window.electronAPI.yaml.read(`${projectPath}/project.yaml`)
      if (result.success && result.data) {
        const data = result.data as Record<string, unknown>
        setProjectName(String(data.title || '小说'))
      }
    } catch {}
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const userConfirmed = window.confirm('当前章节有未保存的内容，是否保存？')
      if (userConfirmed) await handleSave()
    }

    setChapterContent('')
    setActiveChapter(filePath)
    setIsDirty(false)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent, handleSave])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={saveStatus === 'saving' || !activeChapter}
            loading={saveStatus === 'saving'}
          >
            {saveStatus === 'saving'
              ? '保存中...'
              : saveStatus === 'saved'
                ? '已保存 ✓'
                : saveStatus === 'error'
                  ? '保存失败 ↺'
                  : isDirty
                    ? '保存 *'
                    : '已保存'}
          </Button>
          <Button
            icon={<BookOutlined />}
            onClick={() => setExportManagerVisible(true)}
            disabled={!projectRoot}
          >
            导出
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && projectRoot && (
            <CharactersPage
              projectRoot={projectRoot}
              onCharacterClick={(name) => {
                // 可选：切换到大纲并搜索该角色相关内容
              }}
            />
          )}
          {activeTab === 'world' && (
            <SettingsPage projectRoot={projectRoot} />
          )}
          {activeTab === 'facts' && <FactsPanel projectRoot={projectRoot} />}
          {activeTab === 'search' && (
            <VectorSearchPanel
              projectRoot={projectRoot}
              onJumpToChapter={(path) => {
                handleChapterSelect(path)
              }}
            />
          )}
          {activeTab === 'appSettings' && <AppSettingsPage />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              ref={editorRef}
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', borderBottom: '1px solid #e8e8e8' }}>
            <Button
              type={rightPanelTab === 'ai' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('ai')}
            >
              ✏️ AI工具
            </Button>
            <Button
              type={rightPanelTab === 'analysis' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('analysis')}
            >
              📊 分析
            </Button>
          </div>
          {rightPanelTab === 'ai' ? (
            <AIToolsPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              getSelectedText={() => editorRef.current?.getSelectedText() || ''}
              onInsertText={(text) => {
                if (text.startsWith('__REPLACE__')) {
                  const newContent = text.slice('__REPLACE__'.length)
                  setChapterContent(newContent)
                } else {
                  setChapterContent(prev => prev + text)
                }
                setIsDirty(true)
              }}
            />
          ) : (
            <AnalysisPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              projectRoot={projectRoot}
            />
          )}
        </Sider>
      </Layout>

      {/* 项目管理对话框 */}
      <ProjectManager
        visible={projectManagerVisible}
        onClose={() => setProjectManagerVisible(false)}
        onProjectOpened={handleProjectOpened}
      />
      <ExportManager
        visible={exportManagerVisible}
        projectRoot={projectRoot}
        projectName={projectName}
        onClose={() => setExportManagerVisible(false)}
      />
    </Layout>
  )
}

export default Workbench

import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'

// 浏览器环境下替代 path.join 的工具函数
const pathJoin = (...parts: string[]): string => {
  return parts.filter(Boolean).join('/')
}

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!Array.isArray(entries)) return []

      const result: FileEntry[] = []

      for (const entry of entries) {
        const fullPath = pathJoin(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = entry.path  // 统一用真实路径作为 key，保证选中高亮正确

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = pathJoin(projectRoot, 'plots')
        const existsResult = await window.electronAPI.exists(plotsDir)
        if (!existsResult || !existsResult.success || !existsResult.exists) {
          await window.electronAPI.mkdir(plotsDir)
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error) {
        message.error('加载大纲失败')
        console.error(error)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = pathJoin(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      loadDirectory(pathJoin(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: React.Key[]) => {
    if (selectedKeys.length === 0) return
    const key = String(selectedKeys[0])
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

export default OutlineTree

/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState, useCallback } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
